@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
* {
  box-sizing: border-box;
  font-family: "Figtree", sans-serif;
  margin: 0;
  padding: 0;
}

.card {
  background: #fff;
  border: 0.5px solid rgba(0, 0, 0, 0.1);
  border-radius: 10px;
  overflow: hidden;
  padding-bottom: 16px;
}

.card-header {
  padding: 14px 16px;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

.card-title {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

.section-title {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  margin: 16px 16px 8px;
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 0;
  margin: 16px;
  border: 0.5px solid rgba(0, 0, 0, 0.08);
  border-radius: 8px;
}

.meta-item {
  padding: 12px 14px;
  border-right: 0.5px solid rgba(0, 0, 0, 0.06);
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
}

.meta-label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 4px;
}

.meta-value {
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin: 0 16px;
  width: calc(100% - 32px);
}

th {
  text-align: left;
  padding: 8px 10px;
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.08);
}

td {
  padding: 8px 10px;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border-bottom: 0.5px solid rgba(0, 0, 0, 0.06);
}

.empty {
  text-align: center;
  padding: 20px;
  color: #888780;
  font-size: 12px;
  margin: 0 16px;
}

.clickable-row:hover td {
  background: #f9f8f6;
  cursor: pointer;
}

.btn {
  font-family: "Figtree", sans-serif;
  font-size: 12px;
  font-weight: 700;
  padding: 0 16px;
  height: 34px;
  border-radius: 6px;
  border: none;
  cursor: pointer;
}

.btn-primary {
  background: #A3E851;
  color: #05042E;
}

.btn-secondary {
  background: rgba(5, 4, 46, 0.06);
  color: #05042E;
}

.btn-sm {
  height: 28px;
  font-size: 11px;
  padding: 0 12px;
}

.form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin: 16px;
}

.form-group {
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.form-group.full {
  grid-column: 1/-1;
}

label {
  font-size: 10px;
  font-weight: 700;
  color: #888780;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

input, select {
  font-family: "Figtree", sans-serif;
  font-size: 13px;
  font-weight: 600;
  color: #05042E;
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  padding: 8px 10px;
  width: 100%;
}

.signature-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 16px;
  margin: 16px;
}

.signature-block {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.signature-block canvas {
  border: 0.5px solid rgba(0, 0, 0, 0.15);
  border-radius: 6px;
  background: #fafafa;
  touch-action: none;
  width: 100%;
  height: 150px;
}

.form-actions {
  margin: 0 16px;
  display: flex;
  justify-content: flex-end;
}

