function escHtml(str) {
  if (str === null || str === undefined) return '';
  return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
function fmt(d) {
  if (!d) return '—';
  var dt = new Date(d);
  if (isNaN(dt.getTime())) return String(d);
  return dt.toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
var VEHICLES = ['Transit LC60 ECJ', 'Luton HT19 WXB', 'EuroCargo HV66 CKD', 'Van LD23 EFL'];
function renderListView(bookedCollections) {
  var rows = !bookedCollections.length ? '<tr><td colspan="5" class="empty">No booked collections</td></tr>' : bookedCollections.map(function (c) {
    return '<tr data-collection-id="' + c.collection_id + '" class="clickable-row">' + '<td>' + c.collection_id + '</td>' + '<td>' + escHtml(c.address1 || '') + ', ' + escHtml(c.city || '') + '</td>' + '<td>' + fmt(c.collection_date) + '</td>' + '<td>' + escHtml(c.job_type || '—') + '</td>' + '<td><button class="btn btn-primary btn-sm" data-action="open">Open</button></td>' + '</tr>';
  }).join('');
  return '<div class="card">' + '<div class="card-header"><span class="card-title">Booked Collections</span></div>' + '<table><thead><tr><th>ID</th><th>Address</th><th>Date</th><th>Job Type</th><th></th></tr></thead>' + '<tbody>' + rows + '</tbody></table>' + '</div>';
}
function renderExpectedItems(expectedAssets) {
  var items = expectedAssets;
  if (typeof items === 'string') {
    try {
      items = JSON.parse(items || '[]');
    } catch (e) {
      items = [];
    }
  }
  if (!items || !items.length) return '<div class="empty">No expected items listed</div>';
  return '<table><thead><tr><th>Item</th><th>Qty</th></tr></thead><tbody>' + items.map(function (i) {
    return '<tr><td>' + escHtml(i.item) + '</td><td>' + (i.qty || 0) + '</td></tr>';
  }).join('') + '</tbody></table>';
}
function renderLoggedItems(items) {
  if (!items.length) return '<div class="empty">No items logged yet</div>';
  return '<table><thead><tr><th>Item Type</th><th>Qty</th><th>Logged</th></tr></thead><tbody>' + items.map(function (i) {
    return '<tr><td>' + escHtml(i.item_type_name) + '</td><td>' + i.quantity + '</td><td style="font-size:11px">' + fmt(i.created_at) + '</td></tr>';
  }).join('') + '</tbody></table>';
}
function surveyFlag(label, value, notes) {
  var displayValue = value === true ? 'Yes' : value === false ? 'No' : '—';
  var color = value === true ? '#991b1b' : '#05042E';
  return '<div class="meta-item">' + '<div class="meta-label">' + escHtml(label) + '</div>' + '<div class="meta-value" style="color:' + color + ';">' + displayValue + '</div>' + (notes ? '<div style="font-size:11px; color:#888780; margin-top:2px;">' + escHtml(notes) + '</div>' : '') + '</div>';
}
function renderSiteSurvey(detail) {
  if (!detail.surveyed_by) return '<div class="empty">No site survey on record</div>';
  return '<div class="meta-grid" style="grid-template-columns: repeat(3, 1fr);">' + surveyFlag('Vehicle Access', detail.vehicle_access, detail.vehicle_access_notes) + surveyFlag('Parking / Loading Bay', detail.parking_loading_bay, detail.parking_notes) + surveyFlag('Access Restrictions', detail.access_restrictions, detail.access_restriction_notes) + surveyFlag('Time Restrictions', detail.time_restrictions, detail.time_restriction_notes) + surveyFlag('Lift Restrictions', detail.lift_restrictions, detail.lift_notes) + surveyFlag('Narrow Corridors', detail.narrow_corridors, detail.corridor_notes) + surveyFlag('Manual Handling Required', detail.manual_handling_required, detail.manual_handling_notes) + surveyFlag('Security Procedures', detail.security_procedures, detail.security_details) + '<div class="meta-item"><div class="meta-label">Floor Access</div><div class="meta-value">' + escHtml(detail.floor_access_type || '—') + (detail.equipment_floor ? ' — Floor ' + escHtml(detail.equipment_floor) : '') + '</div></div>' + '</div>' + (detail.driver_instructions ? '<div class="meta-item full" style="margin:0 16px 14px; padding:12px 14px; background: rgba(184,134,11,0.08); border-radius:8px;"><div class="meta-label">Driver Instructions</div><div class="meta-value">' + escHtml(detail.driver_instructions) + '</div></div>' : '') + '<div style="margin: 0 16px 16px; font-size:11px; color:#888780;">Surveyed by ' + escHtml(detail.surveyed_by) + ' on ' + fmt(detail.survey_date) + '</div>';
}
function renderFormView(detail, itemTypes, loggedItems, driverName) {
  if (!detail) return '<div class="empty">Loading collection...</div>';
  var vehicleOptions = VEHICLES.map(function (v) {
    return '<option value="' + v + '">' + v + '</option>';
  }).join('');
  var itemTypeOptions = '<option value="">Select item type...</option>' + itemTypes.map(function (it) {
    return '<option value="' + it.item_type_id + '">' + escHtml(it.item_type_name) + '</option>';
  }).join('');
  return '<div class="card">' + '<div class="card-header"><span class="card-title">Job Details — Collection #' + detail.collection_id + '</span></div>' + '<div class="meta-grid">' + '<div class="meta-item"><div class="meta-label">Customer</div><div class="meta-value">' + escHtml(detail.customer_name || '—') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Address</div><div class="meta-value">' + escHtml(detail.address1 || '') + ', ' + escHtml(detail.city || '') + ' ' + escHtml(detail.postcode || '') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Site Contact</div><div class="meta-value">' + escHtml(detail.site_contact || '—') + '</div></div>' + '<div class="meta-item"><div class="meta-label">Instructions</div><div class="meta-value">' + escHtml(detail.instructions || '—') + '</div></div>' + '</div>' + '<div class="section-title">Site Survey</div>' + renderSiteSurvey(detail) + '<div class="section-title">Expected Items</div>' + renderExpectedItems(detail.expected_assets) + '<div class="section-title">Actual Items Collected</div>' + renderLoggedItems(loggedItems) + '<div class="form-grid" style="margin-top:10px;">' + '<div class="form-group"><label>Item Type</label><select id="f_item_type">' + itemTypeOptions + '</select></div>' + '<div class="form-group"><label>Quantity</label><input type="number" id="f_item_qty" value="1" min="1"/></div>' + '<div class="form-group full"><button class="btn btn-primary" id="btn_add_item">+ Add Item</button></div>' + '</div>' + '<div class="section-title">Job Sign-Off</div>' + '<div class="form-grid">' + '<div class="form-group"><label>Vehicle Registration</label><select id="f_vehicle"><option value="">Select vehicle...</option>' + vehicleOptions + '</select></div>' + '<div class="form-group"><label>Driver</label><input type="text" value="' + escHtml(driverName || '') + '" disabled/></div>' + '<div class="form-group full"><label>Customer Name (On-Site)</label><input type="text" id="f_customer_name"/></div>' + '</div>' + '<div class="signature-row">' + '<div class="signature-block">' + '<label>Driver Signature</label>' + '<canvas id="canvas_driver" width="400" height="150"></canvas>' + '<button class="btn btn-secondary btn-sm" data-clear="driver">Clear</button>' + '</div>' + '<div class="signature-block">' + '<label>Customer Signature</label>' + '<canvas id="canvas_client" width="400" height="150"></canvas>' + '<button class="btn btn-secondary btn-sm" data-clear="client">Clear</button>' + '</div>' + '</div>' + '<div class="form-actions" style="margin-top:16px;"><button class="btn btn-primary" id="btn_submit_jobsheet">Submit Job Sheet</button></div>' + '</div>';
}
function renderAll(model) {
  var m = model || {};
  var root = document.getElementById('root');
  if (!m.collection_id) {
    root.innerHTML = renderListView(m.bookedCollections || []);
    wireListEvents();
  } else {
    root.innerHTML = renderFormView(m.collectionDetail, m.itemTypes || [], m.loggedItems || [], m.driverName);
    wireFormEvents();
    setupSignatureCanvas('canvas_driver');
    setupSignatureCanvas('canvas_client');
  }
}
function wireListEvents() {
  document.querySelectorAll('[data-action="open"]').forEach(function (btn) {
    btn.addEventListener('click', function () {
      var row = btn.closest('tr');
      var id = row.dataset.collectionId;
      appsmith.updateModel({
        selectedCollectionId: Number(id)
      });
      appsmith.triggerEvent('onOpenCollection');
    });
  });
}
function wireFormEvents() {
  var addBtn = document.getElementById('btn_add_item');
  if (addBtn) addBtn.addEventListener('click', function () {
    var itemTypeId = document.getElementById('f_item_type').value;
    var qty = document.getElementById('f_item_qty').value;
    if (!itemTypeId) {
      alert('Please select an item type');
      return;
    }
    appsmith.updateModel({
      js_item_type_id: Number(itemTypeId),
      js_item_qty: Number(qty) || 1
    });
    appsmith.triggerEvent('onAddJobSheetItem');
  });
  var submitBtn = document.getElementById('btn_submit_jobsheet');
  if (submitBtn) submitBtn.addEventListener('click', function () {
    var vehicle = document.getElementById('f_vehicle').value;
    var customerName = document.getElementById('f_customer_name').value;
    if (!vehicle) {
      alert('Please select a vehicle');
      return;
    }
    if (!customerName) {
      alert('Please enter customer name');
      return;
    }
    var driverSigCanvas = document.getElementById('canvas_driver');
    var clientSigCanvas = document.getElementById('canvas_client');
    var driverSigData = driverSigCanvas.dataset.hasDrawn === 'true' ? driverSigCanvas.toDataURL('image/png') : null;
    var clientSigData = clientSigCanvas.dataset.hasDrawn === 'true' ? clientSigCanvas.toDataURL('image/png') : null;
    if (!driverSigData) {
      alert('Driver signature required');
      return;
    }
    if (!clientSigData) {
      alert('Customer signature required');
      return;
    }
    appsmith.updateModel({
      js_vehicle: vehicle,
      js_customer_name_onsite: customerName,
      js_driver_signature: driverSigData,
      js_client_signature: clientSigData
    });
    appsmith.triggerEvent('onSubmitJobSheet');
  });
  document.querySelectorAll('[data-clear]').forEach(function (btn) {
    btn.addEventListener('click', function () {
      var canvasId = 'canvas_' + btn.dataset.clear;
      var canvas = document.getElementById(canvasId);
      var ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      canvas.dataset.hasDrawn = 'false';
    });
  });
}
function setupSignatureCanvas(canvasId) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  ctx.strokeStyle = '#05042E';
  ctx.lineWidth = 2;
  ctx.lineCap = 'round';
  canvas.dataset.hasDrawn = 'false';
  var drawing = false;
  function getPos(e) {
    var rect = canvas.getBoundingClientRect();
    var clientX = e.touches ? e.touches[0].clientX : e.clientX;
    var clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return {
      x: clientX - rect.left,
      y: clientY - rect.top
    };
  }
  function start(e) {
    drawing = true;
    canvas.dataset.hasDrawn = 'true';
    var pos = getPos(e);
    ctx.beginPath();
    ctx.moveTo(pos.x, pos.y);
    e.preventDefault();
  }
  function move(e) {
    if (!drawing) return;
    var pos = getPos(e);
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    e.preventDefault();
  }
  function end() {
    drawing = false;
  }
  canvas.addEventListener('mousedown', start);
  canvas.addEventListener('mousemove', move);
  canvas.addEventListener('mouseup', end);
  canvas.addEventListener('mouseleave', end);
  canvas.addEventListener('touchstart', start);
  canvas.addEventListener('touchmove', move);
  canvas.addEventListener('touchend', end);
}
function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function () {
    renderAll(appsmith.model);
    appsmith.triggerEvent('onLoadJobSheet');
  });
  appsmith.onModelChange(function (model) {
    renderAll(model);
  });
}
initWhenReady();

