    '<div class="meta-item"><div class="meta-label">Floor Access</div><div class="meta-value">' + escHtml(detail.floor_access_type || '—') + (detail.equipment_floor ? ' — Floor ' + escHtml(detail.equipment_floor) : '') + '</div></div>' +
  '</div>' +
  (detail.driver_instructions ? '<div class="meta-item full" style="margin:0 16px 14px; padding:12px 14px; background: rgba(184,134,11,0.08); border-radius:8px;"><div class="meta-label">Driver Instructions</div><div class="meta-value">' + escHtml(detail.driver_instructions) + '</div></div>' : '') +
  '<div style="margin: 0 16px 16px; font-size:11px; color:#888780;">Surveyed by ' + escHtml(detail.surveyed_by) + ' on ' + fmt(detail.survey_date) + '</div>';
}

function renderFormView(detail, itemTypes, loggedItems, driverName) {
  if (!detail) return '<div class="empty">Loading collection...</div>';

  var vehicleOptions = VEHICLES.map(function(v) {
    return '<option value="' + v + '">' + v + '</option>';
  }).join('');

  var itemTypeOptions = '<option value="">Select item type...</option>' + itemTypes.map(function(it) {
    return '<option value="' + it.item_type_id + '">' + escHtml(it.item_type_name) + '</option>';
  }).join('');

  return '<div class="card">' +
    '<div class="card-header"><span class="card-title">Job Details — Collection #' + detail.collection_id + '</span></div>' +
    '<div class="meta-grid">' +
      '<div class="meta-item"><div class="meta-label">Customer</div><div class="meta-value">' + escHtml(detail.customer_name || '—') + '</div></div>' +
      '<div class="meta-item"><div class="meta-label">Address</div><div class="meta-value">' + escHtml(detail.address1 || '') + ', ' + escHtml(detail.city || '') + ' ' + escHtml(detail.postcode || '') + '</div></div>' +
      '<div class="meta-item"><div class="meta-label">Site Contact</div><div class="meta-value">' + escHtml(detail.site_contact || '—') + '</div></div>' +
      '<div class="meta-item"><div class="meta-label">Instructions</div><div class="meta-value">' + escHtml(detail.instructions || '—') + '</div></div>' +
    '</div>' +

    '<div class="section-title">Site Survey</div>' +
    renderSiteSurvey(detail) +

    '<div class="section-title">Expected Items</div>' +
    renderExpectedItems(detail.expected_assets) +

    '<div class="section-title">Actual Items Collected</div>' +
    renderLoggedItems(loggedItems) +
    '<div class="form-grid" style="margin-top:10px;">' +
      '<div class="form-group"><label>Item Type</label><select id="f_item_type">' + itemTypeOptions + '</select></div>' +
      '<div class="form-group"><label>Quantity</label><input type="number" id="f_item_qty" value="1" min="1"/></div>' +
      '<div class="form-group full"><button class="btn btn-primary" id="btn_add_item">+ Add Item</button></div>' +
    '</div>' +

    '<div class="section-title">Job Sign-Off</div>' +
    '<div class="form-grid">' +
      '<div class="form-group"><label>Vehicle Registration</label><select id="f_vehicle"><option value="">Select vehicle...</option>' + vehicleOptions + '</select></div>' +
      '<div class="form-group"><label>Driver</label><input type="text" value="' + escHtml(driverName || '') + '" disabled/></div>' +
      '<div class="form-group full"><label>Customer Name (On-Site)</label><input type="text" id="f_customer_name"/></div>' +
    '</div>' +

    '<div class="signature-row">' +
      '<div class="signature-block">' +
        '<label>Driver Signature</label>' +
        '<canvas id="canvas_driver" width="400" height="150"></canvas>' +
        '<button class="btn btn-secondary btn-sm" data-clear="driver">Clear</button>' +
      '</div>' +
      '<div class="signature-block">' +
        '<label>Customer Signature</label>' +
        '<canvas id="canvas_client" width="400" height="150"></canvas>' +
        '<button class="btn btn-secondary btn-sm" data-clear="client">Clear</button>' +
      '</div>' +
    '</div>' +

    '<div class="form-actions" style="margin-top:16px;"><button class="btn btn-primary" id="btn_submit_jobsheet">Submit Job Sheet</button></div>' +
  '</div>';
}

function renderAll(model) {
  var m = model || {};
  var root = document.getElementById('root');

  if (!m.collection_id) {
    root.innerHTML = renderListView(m.bookedCollections || []);
    wireListEvents();
  } else {
    root.innerHTML = renderFormView(m.collectionDetail, m.itemTypes || [], m.loggedItems || [], m.driverName);
    wireFormEvents();
    setupSignatureCanvas('canvas_driver');
    setupSignatureCanvas('canvas_client');
  }
}

function wireListEvents() {
  document.querySelectorAll('[data-action="open"]').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var row = btn.closest('tr');
      var id = row.dataset.collectionId;
      appsmith.updateModel({ selectedCollectionId: Number(id) });
      appsmith.triggerEvent('onOpenCollection');
    });
  });
}

function wireFormEvents() {
  var addBtn = document.getElementById('btn_add_item');
  if (addBtn) addBtn.addEventListener('click', function() {
    var itemTypeId = document.getElementById('f_item_type').value;
    var qty = document.getElementById('f_item_qty').value;
    if (!itemTypeId) { alert('Please select an item type'); return; }
    appsmith.updateModel({ js_item_type_id: Number(itemTypeId), js_item_qty: Number(qty) || 1 });
    appsmith.triggerEvent('onAddJobSheetItem');
  });

  var submitBtn = document.getElementById('btn_submit_jobsheet');
  if (submitBtn) submitBtn.addEventListener('click', function() {
    var vehicle = document.getElementById('f_vehicle').value;
    var customerName = document.getElementById('f_customer_name').value;
    if (!vehicle) { alert('Please select a vehicle'); return; }
    if (!customerName) { alert('Please enter customer name'); return; }

    var driverSigCanvas = document.getElementById('canvas_driver');
    var clientSigCanvas = document.getElementById('canvas_client');
    var driverSigData = driverSigCanvas.dataset.hasDrawn === 'true' ? driverSigCanvas.toDataURL('image/png') : null;
    var clientSigData = clientSigCanvas.dataset.hasDrawn === 'true' ? clientSigCanvas.toDataURL('image/png') : null;

    if (!driverSigData) { alert('Driver signature required'); return; }
    if (!clientSigData) { alert('Customer signature required'); return; }

    appsmith.updateModel({
      js_vehicle: vehicle,
      js_customer_name_onsite: customerName,
      js_driver_signature: driverSigData,
      js_client_signature: clientSigData
    });
    appsmith.triggerEvent('onSubmitJobSheet');
  });

  document.querySelectorAll('[data-clear]').forEach(function(btn) {
    btn.addEventListener('click', function() {
      var canvasId = 'canvas_' + btn.dataset.clear;
      var canvas = document.getElementById(canvasId);
      var ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      canvas.dataset.hasDrawn = 'false';
    });
  });
}

function setupSignatureCanvas(canvasId) {
  var canvas = document.getElementById(canvasId);
  if (!canvas) return;
  var ctx = canvas.getContext('2d');
  ctx.strokeStyle = '#05042E';
  ctx.lineWidth = 2;
  ctx.lineCap = 'round';
  canvas.dataset.hasDrawn = 'false';

  var drawing = false;

  function getPos(e) {
    var rect = canvas.getBoundingClientRect();
    var clientX = e.touches ? e.touches[0].clientX : e.clientX;
    var clientY = e.touches ? e.touches[0].clientY : e.clientY;
    return { x: clientX - rect.left, y: clientY - rect.top };
  }

  function start(e) {
    drawing = true;
    canvas.dataset.hasDrawn = 'true';
    var pos = getPos(e);
    ctx.beginPath();
    ctx.moveTo(pos.x, pos.y);
    e.preventDefault();
  }

  function move(e) {
    if (!drawing) return;
    var pos = getPos(e);
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    e.preventDefault();
  }

  function end() { drawing = false; }

  canvas.addEventListener('mousedown', start);
  canvas.addEventListener('mousemove', move);
  canvas.addEventListener('mouseup', end);
  canvas.addEventListener('mouseleave', end);
  canvas.addEventListener('touchstart', start);
  canvas.addEventListener('touchmove', move);
  canvas.addEventListener('touchend', end);
}

function initWhenReady() {
  if (typeof appsmith === 'undefined' || !appsmith.onReady) {
    setTimeout(initWhenReady, 50);
    return;
  }
  appsmith.onReady(function() {
    renderAll(appsmith.model);
    appsmith.triggerEvent('onLoadJobSheet');
  });
  appsmith.onModelChange(function(model) {
    renderAll(model);
  });
}

initWhenReady();
